import{_ as t,p as r,q as i,a1 as g}from"./framework-e0dd9823.js";const e={},s=g('<h1 id="git-常用指令" tabindex="-1"><a class="header-anchor" href="#git-常用指令" aria-hidden="true">#</a> Git-常用指令</h1><h4 id="git-基本命令" tabindex="-1"><a class="header-anchor" href="#git-基本命令" aria-hidden="true">#</a> git 基本命令</h4><p><strong>git init</strong> 初始化一个 git 仓库</p><p><strong>git add fileName</strong> 把文件提交到缓存区</p><p><strong>git rm fileName</strong> 删除缓存区的文件</p><p><strong>git commit -m &quot;提交的备注信息&quot;</strong> 把缓存区的内容提交到 git 仓库</p><p><strong>git status</strong> 查看 git 仓库状态</p><p><strong>git diff fileName</strong> 比较未提交文件差异</p><p><strong>git log</strong> 查看 git 日志</p><p><strong>git reset 版本号</strong> 回退到某一个版本</p><p><strong>git reset HEAD^</strong> 回退到上一个版本，^代表上一个，以此类推</p><p><strong>git reflog</strong> 查看仓库历史操作记录</p><h4 id="git-线上指令" tabindex="-1"><a class="header-anchor" href="#git-线上指令" aria-hidden="true">#</a> git 线上指令</h4><p><strong>git clone 仓库地址</strong> 克隆线上仓库到本地</p><p><strong>git push 仓库地址</strong> 上传本地仓库到线上</p><p><strong>git pull</strong> 拉取线上 仓库到本地</p>',16),n=[s];function o(a,p){return r(),i("div",null,n)}const c=t(e,[["render",o],["__file","Git.html.vue"]]);export{c as default};
